func SetParams(dst, src Params) {
	for k, v := range src {
		vv, found := dst[k]
		if !found {
			dst[k] = v
		} else {
			switch vvv := vv.(type) {
			case Params:
				if pv, ok := v.(Params); ok {
					SetParams(vvv, pv)
				} else {
					dst[k] = v
				}
			default:
				dst[k] = v
			}
		}
	}
}
